using System;
using System.Security.Cryptography;
using System.Text;

public class CreditCardEncryptor
{
    private static readonly string EncryptionKey = "your_encryption_key";

    public static string Encrypt(string creditCardNumber)
    {
        var data = Encoding.UTF8.GetBytes(creditCardNumber);
        using (var aes = Aes.Create())
        {
            aes.Key = Convert.FromBase64String(EncryptionKey);
            aes.Mode = CipherMode.CBC;
            aes.Padding = PaddingMode.PKCS7;

            var encryptedData = aes.Encrypt(data, null);
            return Convert.ToBase64String(encryptedData);
        }
    }

    public static string Decrypt(string encryptedCreditCardNumber)
    {
        var data = Convert.FromBase64String(encryptedCreditCardNumber);
        using (var aes = Aes.Create())
        {
            aes.Key = Convert.FromBase64String(EncryptionKey);
            aes.Mode = CipherMode.CBC;
            aes.Padding = PaddingMode.PKCS7;

            var decryptedData = aes.Decrypt(data, null);
            return Encoding.UTF8.GetString(decryptedData);
        }
    }
}
